import { FileId, FileMetadata } from '../types';
import { Readable } from 'stream';

/**
 * Represents an object storage service capable of retrieving file metadata and streaming file content.
 */
export interface ObjectStorageService {
  /**
   * Retrieves metadata for a given file ID.
   * @param fileId The ID of the file.
   * @returns A Promise resolving to the file's metadata, or null if not found.
   */
  getFileMetadata(fileId: FileId): Promise<FileMetadata | null>;

  /**
   * Streams the content of a file from storage.
   * @param storagePath The internal storage path of the file.
   * @returns A Promise resolving to a Readable stream of the file content, or null if the file cannot be streamed.
   */
  streamFileContent(storagePath: string): Promise<Readable | null>;
}

/**
 * A mock implementation of ObjectStorageService for demonstration purposes.
 * Stores files in memory and simulates streaming.
 */
export class MockObjectStorageService implements ObjectStorageService {
  private files: Map<FileId, FileMetadata & { content: Buffer }> = new Map();

  constructor() {
    // Seed with some mock data
    this.addFile({
      id: 'file-123',
      fileName: 'document.pdf',
      contentType: 'application/pdf',
      ownerTeamId: 'team-alpha',
      storagePath: 'path/to/document.pdf',
    }, Buffer.from('This is a mock PDF content for file-123.'));

    this.addFile({
      id: 'file-456',
      fileName: 'image.png',
      contentType: 'image/png',
      ownerTeamId: 'team-beta',
      storagePath: 'path/to/image.png',
    }, Buffer.from('This is a mock PNG content for file-456.'));

    this.addFile({
      id: 'file-789',
      fileName: 'report.xlsx',
      contentType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      ownerTeamId: 'team-alpha',
      storagePath: 'path/to/report.xlsx',
    }, Buffer.from('This is a mock XLSX content for file-789.'));
  }

  private addFile(metadata: Omit<FileMetadata, 'size'>, content: Buffer) {
    const fullMetadata: FileMetadata & { content: Buffer } = {
      ...metadata,
      size: content.length,
      content: content,
    };
    this.files.set(metadata.id, fullMetadata);
  }

  async getFileMetadata(fileId: FileId): Promise<FileMetadata | null> {
    const file = this.files.get(fileId);
    if (!file) {
      return null;
    }
    // Return a copy without the content buffer
    const { content, ...metadata } = file;
    return metadata;
  }

  async streamFileContent(storagePath: string): Promise<Readable | null> {
    const file = Array.from(this.files.values()).find(f => f.storagePath === storagePath);
    if (!file) {
      return null;
    }
    // Simulate a stream from the buffer
    return Readable.from(file.content);
  }
}
