import { FileMetadata, UserContext } from '../types';

/**
 * Service for handling authorization checks.
 */
export class AuthService {
  /**
   * Checks if a user has access to a specific file.
   * Access is granted if the user is a member of the file's owning team.
   * @param userContext The context of the authenticated user.
   * @param fileMetadata The metadata of the file being accessed.
   * @returns True if the user has access, false otherwise.
   */
  hasAccessToFile(userContext: UserContext, fileMetadata: FileMetadata): boolean {
    return userContext.teamIds.includes(fileMetadata.ownerTeamId);
  }
}
