import { Hono } from 'hono';
import { ObjectStorageService } from '../services/objectStorage';
import { AuthService } from '../services/auth';
import { UserContext } from '../types';
import { Readable } from 'stream';

// Define a type for the Hono context variables that might be injected
// In a real app, this would come from middleware (e.g., authentication middleware)
interface Variables {
  userContext: UserContext;
}

/**
 * Creates a Hono application for file download routes.
 * @param objectStorageService The service for interacting with object storage.
 * @param authService The service for authorization checks.
 * @returns A Hono app instance with the download route.
 */
export function createDownloadApp(
  objectStorageService: ObjectStorageService,
  authService: AuthService
) {
  const app = new Hono<{ Variables: Variables }>();

  app.get('/:fileId', async (c) => {
    const fileId = c.req.param('fileId');
    const userContext = c.get('userContext'); // Assumed to be set by an auth middleware

    if (!userContext) {
      // This should ideally be caught by an earlier auth middleware returning 401/403
      // But as a fallback, if userContext is missing, we deny access.
      return c.text('Unauthorized', 401);
    }

    // 1. Retrieve file metadata
    const fileMetadata = await objectStorageService.getFileMetadata(fileId);

    if (!fileMetadata) {
      // File not found, return 404
      return c.text('File not found', 404);
    }

    // 2. Authorize access
    const hasAccess = authService.hasAccessToFile(userContext, fileMetadata);

    if (!hasAccess) {
      // Access denied, return 404 to avoid existence leak
      return c.text('File not found', 404);
    }

    // 3. Stream file content
    const fileStream = await objectStorageService.streamFileContent(fileMetadata.storagePath);

    if (!fileStream) {
      // Could not stream the file (e.g., internal storage error)
      console.error(`Failed to stream file content for storage path: ${fileMetadata.storagePath}`);
      return c.text('Internal Server Error', 500);
    }

    // Hono can directly handle Node.js Readable streams
    // Set appropriate headers for file download
    c.header('Content-Type', fileMetadata.contentType);
    c.header('Content-Disposition', `attachment; filename="${fileMetadata.fileName}"`);
    c.header('Content-Length', fileMetadata.size.toString());

    return c.body(fileStream as unknown as ReadableStream); // Cast for Hono's ResponseBody type
  });

  return app;
}
