```aether:src/index.ts
import { Hono } from 'hono';
import { createDownloadApp } from './routes/download';
import { MockObjectStorageService } from './services/objectStorage';
import { AuthService } from './services/auth';
import { UserContext } from './types';

const app = new Hono();

// Initialize services
const objectStorageService = new MockObjectStorageService();
const authService = new AuthService();

// --- Mock Authentication Middleware ---
// In a real application, this middleware would extract user information
// from JWTs, session tokens, etc., and populate `c.set('userContext', ...)`.
app.use('*', async (c, next) => {
  // For demonstration, we'll use a query parameter or a hardcoded user.
  // Example: /download/file-123?user=user-1&teams=team-alpha,team-beta
  const userId = c.req.query('user') || 'mock-user-1';
  const teamIdsParam = c.req.query('teams') || 'team-alpha'; // Default to team-alpha
  const teamIds = teamIdsParam.split(',');

  const userContext: UserContext = {
    userId: userId,
    teamIds: teamIds,
  };

  c.set('userContext', userContext);
  await next();
});
// --- End Mock Authentication Middleware ---

// Mount the download application under /download
app.route('/download', createDownloadApp(objectStorageService, authService));

// Basic root route
app.get('/', (c) => {
  return c.text('Welcome to the file download service!');
});

// Start the server
const port = 3000;
console.log(`Server is running on http://localhost:${port}`);
console.log(`Try:
  - http://localhost:${port}/download/file-123?user=user-1&teams=team-alpha (Access granted)
  - http://localhost:${port}/download/file-456?user=user-1&teams=team-alpha (Access denied, returns 404)
  - http://localhost:${port}/download/file-456?user=user-2&teams=team-beta (Access granted)
  - http://localhost:${port}/download/non-existent-file?user=user-1&teams=team-alpha (File not found, returns 404)
`);

export default {
  port,
  fetch: app.fetch,
};
